      "text": "Asmaweta Behrni /\nfchetrdefmits un diwi.\n"
    },
    {
      "n": 25,
      "column": "left",
      "text": "Tee Behrni no Kiriat A-\nrim/ Rawira un Beërots/ fept-\nafimts tschetrdefmits un trihs.\n"
    },
    {
      "n": 26,
      "column": "left",
      "text": "Tee Behrni no Rahmas\nn Gabas/ fechsfimts diwidef-\nmts un weens.\n"
    },
    {
      "n": 27,
      "column": "left",
      "text": "Tee Wihri no Mikmas/\nmts diwidefmits un diwi.\n"
    },
    {
      "n": 28,
      "column": "left",
      "text": "Tee Wihri no Betelesun\njas/ diwisimts diwidefmits un\nihs.\n"
    },
    {
      "n": 29,
      "column": "left",
      "text": "Tee Behrni no Nebus/\nezdewmits un diwi.\n"
    },
    {
      "n": 30,
      "column": "left",
      "text": "Tee Behrni no Maḃbis/\nnis peezdefmits un jefchi.\n"
    },
    {
      "n": 31,
      "column": "left",
      "text": "Ta ohtra Elama Behr-\n/ tuhktoschi peezdefmits un\nhetri.\n"
    },
    {
      "n": 32,
      "column": "left",
      "text": "Arima Behrni / trihs-\nmts un diwidefmits.\n"
    },
    {
      "n": 33,
      "column": "left",
      "text": "Tee Behrni no Lodadida\nOnus/ feptinfimts diwidef-\nts un peezi.\n"
    },
    {
      "n": 34,
      "column": "left",
      "text": "Jereiis Behrni / trihs-\nmts tschetrdefmits un peezi.\n"
    },
    {
      "n": 35,
      "column": "left",
      "text": "Senaibs Behrni / trihs\nhksfichi/ fechsfimts un trihs-\nimts.\n"
    },
    {
      "n": 36,
      "column": "left",
      "text": "Tee Preesteri. Jedajus\nbrni/ no Jesuiis Namna/de-\nsimts feptindefmits un trihs.\n"
    },
    {
      "n": 37,
      "column": "right",
      "text": "Jimmera Behrni / tuhe-\nstoschi peezdefmits un diwi.\n"
    },
    {
      "n": 38,
      "column": "right",
      "text": "Pasura Behrni/ tuhksfo-\nschi diwitimts tschetrdefmits u-\nseptini.\n"
    },
    {
      "n": 39,
      "column": "right",
      "text": "Arima Behrni / tuhksfo-\nschi/un feptixpadezmits.\n"
    },
    {
      "n": 40,
      "column": "right",
      "text": "Tee Lewiti. Jesuiis un\nRadinteta Behrni/ no Odawi-\njus Behrneem/ feptindefmits un\ntschetr.\n"
    },
    {
      "n": 41,
      "column": "right",
      "text": "Tee Dseedataji. Affa-\nwa Behrni / fimts diwidefmits\nun astoni.\n"
    },
    {
      "n": 42,
      "column": "right",
      "text": "To Wahrtosarga\nBehrni. Salluma Behrni/ A-\nteka Behrni/ Talinoxa Behrni/\nAkuba Behrni / Atita Behrni/\nSobaja Behrni / wiisi / fimts\ntrihsdefmits un dewini.\n"
    },
    {
      "n": 43,
      "column": "right",
      "text": "Tee Netinim. Jiifs Behr-\nni/ Asuwa Behrni / Tabaota\nBehrni.\n"
    },
    {
      "n": 44,
      "column": "right",
      "text": "Kerosa Behrni/ Sing\nBehrni/ Padona Behrni.\n"
    },
    {
      "n": 45,
      "column": "right",
      "text": "Lebana Behrni/ Agabas\nBehrni/Akuba Behrni.\n"
    },
    {
      "n": 46,
      "column": "right",
      "text": "Agaba Behrni/ Samla-\nja Behrni/ Anana Behrni.\n"
    },
    {
      "n": 47,
      "column": "right",
      "text": "Giddeka Behrni/ Gaira\nBehrni/ Reajus Behrni.\n"
    },
    {
      "n": 48,
      "column": "right",
      "text": "Rezina Behrni/ Nekoda\nBehrni/ Gasama Behrni.\n"
    },
    {
      "n": 49,
      "column": "right",
      "text": "Usus Behrni/ Puffeits\nBehrni/ Bestajus Behrni.\n"
    },
    {
      "n": 50,
      "column": "right",
      "text": "Asnus Behrni / Meis-\nnima Behrni / Newustuna\nBehrni.\n"
    },
    {
      "n": 51,
      "column": "right",
      "text": "Bakbuka Behrni / Aku-\nwa Behrni/ Arura Behrni.\n"
    }
